"use client";

import { useState, useEffect } from "react";

interface OnboardingProps {
    onComplete: () => void;
}

const steps = [
    {
        icon: "●",
        title: "Project Meow",
        description: "An advanced workstation companion designed to monitor and respond to your digital focus.",
    },
    {
        icon: "○",
        title: "Kinetic Link",
        description: "Local neural processing for hand-gesture recognition and proximity awareness.",
        detail: "PRIVACY_SECURED / NO_DATA_EGRESS",
    },
    {
        icon: "◌",
        title: "Focus Uplink",
        description: "Behavioral analysis based on active application states and work-cycle patterns.",
        detail: "REQUIRES_TRACKER_SUBSYSTEM",
    }
];

export default function Onboarding({ onComplete }: OnboardingProps) {
    const [currentStep, setCurrentStep] = useState(0);
    const [isVisible, setIsVisible] = useState(false);
    const [isExiting, setIsExiting] = useState(false);

    useEffect(() => {
        setIsVisible(true);
    }, []);

    const handleNext = () => {
        if (currentStep < steps.length - 1) {
            setCurrentStep(prev => prev + 1);
        } else {
            setIsExiting(true);
            setTimeout(onComplete, 800);
        }
    };

    return (
        <div className={`fixed inset-0 z-[100] flex items-center justify-center bg-black transition-opacity duration-1000 ${isVisible && !isExiting ? "opacity-100" : "opacity-0"}`}>

            <div className="relative w-full max-w-lg px-8">
                <div className="flex flex-col items-center text-center">

                    {/* Progress Dots */}
                    <div className="flex gap-2 mb-12">
                        {steps.map((_, i) => (
                            <div
                                key={i}
                                className={`h-0.5 transition-all duration-500 rounded-full ${i === currentStep ? "w-12 bg-white" : "w-3 bg-white/10"}`}
                            />
                        ))}
                    </div>

                    {/* Step Content */}
                    <div key={currentStep} className="animate-greeting-pop flex flex-col items-center">
                        <div className="text-4xl font-light text-white mb-10 tracking-[0.2em]">
                            {steps[currentStep].icon}
                        </div>

                        <h1 className="text-white text-3xl font-light tracking-[0.4em] uppercase mb-8">
                            {steps[currentStep].title}
                        </h1>

                        <p className="text-white/40 text-lg font-light leading-relaxed mb-4 max-w-sm">
                            {steps[currentStep].description}
                        </p>

                        {steps[currentStep].detail && (
                            <div className="px-5 py-2 mt-4 rounded-sm border border-white/5 text-[9px] text-white/20 uppercase tracking-[0.3em] mb-12 font-mono">
                                {steps[currentStep].detail}
                            </div>
                        )}

                        <button
                            onClick={handleNext}
                            className="group relative px-14 py-4 mt-8 overflow-hidden rounded-full border border-white/10 transition-all hover:border-white/30 hover:bg-white active:scale-95 duration-500"
                        >
                            <span className="relative text-white group-hover:text-black font-light tracking-[0.4em] text-[10px] uppercase transition-colors duration-500">
                                {currentStep === steps.length - 1 ? "Initialize" : "Execute"}
                            </span>
                        </button>
                    </div>

                    {/* Footer Metadata */}
                    <div className="fixed bottom-12 left-1/2 -translate-x-1/2 text-[8px] text-white/5 font-mono tracking-[0.5em] uppercase pointer-events-none">
                        System_Manifest_v1.0 // Auth: Established
                    </div>
                </div>
            </div>

            <style jsx>{`
        @keyframes fade-in-up {
          from { opacity: 0; transform: translateY(20px); }
          to { opacity: 1; transform: translateY(0); }
        }
        .animate-fade-in-up {
          animation: fade-in-up 0.8s cubic-bezier(0.22, 1, 0.36, 1) forwards;
        }
      `}</style>
        </div>
    );
}
